import React, { useState } from 'react';
import { getContracts, getUser } from '../utils/web3';

function MintForm() {
  const [nftType, setNftType] = useState('721');
  const [tokenName, setTokenName] = useState('');
  const [description, setDescription] = useState('');
  const [imageUrl, setImageUrl] = useState('');
  const [imageFile, setImageFile] = useState(null);
  const [imagePreview, setImagePreview] = useState('');
  const [amount, setAmount] = useState('1');
  const [royalty, setRoyalty] = useState('10');
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState({ type: '', text: '' });

  const handleImageUpload = (e) => {
    const file = e.target.files[0];
    if (file) {
      if (file.size > 5 * 1024 * 1024) {
        setMessage({ type: 'error', text: 'Image size must be less than 5MB' });
        return;
      }
      
      if (!file.type.startsWith('image/')) {
        setMessage({ type: 'error', text: 'Please upload an image file' });
        return;
      }
      
      setImageFile(file);
      
      // Create preview
      const reader = new FileReader();
      reader.onloadend = () => {
        setImagePreview(reader.result);
        setImageUrl(reader.result); // Use data URL for now
      };
      reader.readAsDataURL(file);
    }
  };

  const handleMint = async () => {
    if (!tokenName || !description || !imageFile) {
      setMessage({ type: 'error', text: 'Please fill all required fields and upload an image' });
      return;
    }

    setLoading(true);
    setMessage({ type: '', text: '' });

    try {
      const { marketplace, erc721, erc1155 } = getContracts();
      const { address } = getUser();

      if (!address) {
        throw new Error('Please connect your wallet first');
      }

      // Create metadata JSON
      const metadata = {
        name: tokenName,
        description: description,
        image: imageUrl,
        attributes: [],
        createdAt: new Date().toISOString()
      };

      // For demo, we'll use the metadata as a string
      // In production, you'd upload this to IPFS
      const metadataString = JSON.stringify(metadata);
      
      const royaltyFraction = Math.floor(parseFloat(royalty) * 100); // Convert to basis points

      if (nftType === '721') {
        // Mint ERC721
        const tx = await erc721.safeMint(
          address,
          metadataString,
          address,
          royaltyFraction
        );
        
        await tx.wait();
        setMessage({ 
          type: 'success', 
          text: 'ERC721 NFT minted successfully!' 
        });
      } else {
        // Mint ERC1155
        const tx = await erc1155.mint(
          address,
          parseInt(amount),
          metadataString,
          address,
          royaltyFraction,
          "0x"
        );
        
        await tx.wait();
        setMessage({ 
          type: 'success', 
          text: `ERC1155 NFT minted successfully! Amount: ${amount}` 
        });
      }

      // Reset form
      setTokenName('');
      setDescription('');
      setImageUrl('');
      setImageFile(null);
      setImagePreview('');
      
    } catch (error) {
      console.error("Minting error:", error);
      setMessage({ 
        type: 'error', 
        text: error.message || 'Failed to mint NFT' 
      });
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="section">
      <h2 className="section-title">Mint New NFT</h2>
      
      <div className="form-group">
        <label>NFT Type</label>
        <select 
          value={nftType} 
          onChange={(e) => setNftType(e.target.value)}
        >
          <option value="721">ERC-721 (Unique)</option>
          <option value="1155">ERC-1155 (Multiple)</option>
        </select>
      </div>

      <div className="form-group">
        <label>Token Name *</label>
        <input 
          type="text" 
          value={tokenName}
          onChange={(e) => setTokenName(e.target.value)}
          placeholder="Enter NFT name"
        />
      </div>

      <div className="form-group">
        <label>Description *</label>
        <textarea 
          value={description}
          onChange={(e) => setDescription(e.target.value)}
          placeholder="Describe your NFT"
          rows="3"
        />
      </div>

      <div className="form-group">
        <label>Upload Image *</label>
        <input 
          type="file" 
          accept="image/*"
          onChange={handleImageUpload}
          style={{ display: 'none' }}
          id="image-upload"
        />
        <label 
          htmlFor="image-upload"
          style={{
            display: 'block',
            padding: '12px',
            border: '2px dashed #00ff00',
            borderRadius: '8px',
            textAlign: 'center',
            cursor: 'pointer',
            backgroundColor: '#1a1a2e',
            color: '#00ff00'
          }}
        >
          {imageFile ? `Selected: ${imageFile.name}` : 'Click to upload image'}
        </label>
        
        {imagePreview && (
          <div style={{ marginTop: '10px', textAlign: 'center' }}>
            <img 
              src={imagePreview} 
              alt="Preview" 
              style={{ 
                maxWidth: '200px', 
                maxHeight: '200px', 
                borderRadius: '8px',
                border: '1px solid #00ff00'
              }} 
            />
          </div>
        )}
        
        <small>Supported formats: JPG, PNG, GIF. Max size: 5MB</small>
      </div>

      {nftType === '1155' && (
        <div className="form-group">
          <label>Amount</label>
          <input 
            type="number" 
            value={amount}
            onChange={(e) => setAmount(e.target.value)}
            min="1"
            placeholder="Number of copies"
          />
        </div>
      )}

      <div className="form-group">
        <label>Royalty Percentage (%)</label>
        <input 
          type="number" 
          value={royalty}
          onChange={(e) => setRoyalty(e.target.value)}
          min="0"
          max="50"
          step="0.1"
          placeholder="e.g., 10 for 10%"
        />
        <small>Earn this percentage on secondary sales</small>
      </div>

      <button 
        className="submit-btn"
        onClick={handleMint}
        disabled={loading}
      >
        {loading ? 'Minting...' : 'Mint NFT'}
      </button>

      {message.text && (
        <div className={message.type}>
          {message.text}
        </div>
      )}

      <div style={{ marginTop: '20px', fontSize: '14px', color: '#aaa' }}>
        <strong>Note:</strong> For production, integrate with IPFS/Pinata to upload 
        images and metadata. Update the IPFS_CONFIG in utils/config.js with your Pinata keys.
      </div>
    </div>
  );
}

export default MintForm;
